css:
@media print {
    @page {
        size: 100mm 150mm;
        margin: 0;
    }
}

body {
    margin: 0;
    padding: 0;
    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
}

.shipping-label {
    width: 100mm;
    height: 150mm;
    padding: 6mm;
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
}

.header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid #000;
    padding-bottom: 3px;
    margin-bottom: 4px;
}

.logo {
    max-height: 22px;
}

.section {
    margin-bottom: 3px;
}

.row {
    display: flex;
    justify-content: space-between;
    margin-bottom: 1px;
    font-size: 10px;
    line-height: 1.2;
}

.section.dashed {
    border-top: 1px dashed #000;
    padding-top: 4px;

    flex-grow: 1;   /* This pushes QR to bottom */
}
.two-col {
    display: flex;
    justify-content: space-between;
}

.right {
    text-align: right;
}

.row span:last-child {
    text-align: right;
    flex: 1;
}

/* ===== SHIPPING LABEL LAYOUT OPTIMIZED ===== */

.shipping-label {
    width: 100mm;
    height: 150mm;
    padding: 6mm 8mm 8mm 8mm;   /* slightly tighter top padding */
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
}

/* Make middle content flexible */
.section.dashed {
    flex-grow: 1;              /* pushes QR section to bottom */
}

/* ===== QR SECTION ===== */

.barcode-section {
    display: flex;
    justify-content: space-between;
    gap: 6px;

    margin-top: 4px;
    height: 105px;        /* Reserved fixed space */
    flex-shrink: 0;       /* Prevent shrinking */
}

.barcode-section figure {
    flex: 1;
    margin: 0;
    text-align: center;
}

.barcode {
    width: 100%;
    height: 85px;
    object-fit: contain;
}

.barcode-section figcaption {
    font-size: 9px;
    margin-top: 2px;
}

.outsourced-label {
    width: 100%;
    max-height: 150mm;
    object-fit: contain;
}

.page-break {
    page-break-after: always;
}
